import Calculation from './Calculation';

export default class CalculationMagic extends Calculation {
  dpsType = 'magic';

  invisibleMagicDamageBonus = 0;

  maxHitBonus = 0;

  constructor(loadout, target) {
    super(loadout, target, 'magic');
  }

  get maxHit() {
    let max;
    if (this.spell) {
      max = this.spellMaxHit;
    } else if (this.isSalamander()) {
      max = this.salamanderMaxHit;
    }

    max += this.maxHitBonus;
    max += Math.floor(max * this.magicDamageBonus);
    max += Math.floor(max * this.targetSpecificBonus);

    return this.processValue('damage', max);
  }

  get spellMaxHit() {
    let max = 0;
    if (this.isStandardSpell() || this.isAncientSpell()) {
      max = this.spell.baseMaxHit;
      if (this.isGodSpell() && this.isCharged()) {
        max += 10;
      }
      if (this.isMagicDart()) {
        if (this.isEnchantedSlayerStaff()) {
          max = Math.floor(this.effectiveStrength * (1 / 6)) + 13;
        } else {
          max = Math.floor(this.effectiveStrength * 0.1) + 10;
        }
      }
      if (this.isPowered()) {
        max = this.spell.baseMaxHit;
        max += Math.max(0, (this.effectiveStrength - 75) / 3);
      }
    } else if (this.isPowered()) {
      max = this.spell.baseMaxHit;
      if (!this.isCrystalStaff()) {
        max += Math.max(0, Math.floor((this.visibleAttackLevel - 75) / 3));
      }
    }
    return max;
  }

  get salamanderMaxHit() {
    let bonus;
    switch (this.salamanderColor) {
      case 'swamp':
        bonus = 56;
        break;
      case 'orange':
        bonus = 59;
        break;
      case 'red':
        bonus = 77;
        break;
      case 'black':
        bonus = 92;
        break;
    }
    return Math.floor(0.5 + this.visibleAttackLevel * (64 + bonus) / 640);
  }

  isSalamander() {
    return /^(Swamp|Orange|Red|Black)\s(salamander|lizard)$/.test(this.loadout.weapon.name);
  }

  isStandardSpell() {
    return this.spell.attributes.includes('standard');
  }

  isAncientSpell() {
    return this.spell.attributes.includes('ancients');
  }

  isGodSpell() {
    return this.spell.attributes.includes('god');
  }

  isCharged() {
    return this.settings.isCharged;
  }

  isPowered() {
    return this.spell && this.spell.attributes.includes('powered');
  }

  isCrystalStaff() {
    return this.spell && (this.spell.name.includes('Crystal staff') || this.spell.name.includes('Corrupted staff'));
  }

  isMagicDart() {
    return this.spell.name === 'Magic dart';
  }

  isEnchantedSlayerStaff() {
    return /Slayer's staff \(e\)/.test(this.loadout.weapon.name);
  }

  get salamanderColor() {
    const sallyName = this.loadout.weapon.name;
    return sallyName.split(' ')[0].toLowerCase();
  }

  get attackSpeed() {
    let baseAttackSpeed = 5;
    if (this.spell) {
      baseAttackSpeed = this.spell.castSpeed;
    }
    if (this.transformers.has('attackSpeed')) {
      for (const fn of this.transformers.get('attackSpeed')) {
        if (typeof fn === 'function') {
          baseAttackSpeed = fn.call(undefined, baseAttackSpeed, this);
        }
      }
    }
    if (this.modifiers.has('attackSpeed')) {
      for (const value of this.modifiers.get('attackSpeed')) {
        baseAttackSpeed = Math.ceil(baseAttackSpeed * value);
      }
    }
    return baseAttackSpeed;
  }

  get magicDamageBonus() {
    // strengthBonus is the +% magic damage on stat sheet
    return (this.strengthBonus + this.invisibleMagicDamageBonus) / 100;
  }

  get targetSpecificBonus() {
    // !IMPORTANT! toFixed(2) is needed because apparently 1.15 - 1 === 0.1499999...
    return (Math.max(this.bonuses.undead, this.bonuses.slayer) - 1).toFixed(2);
  }
}
